# escalation_engine.py
import time
from dataclasses import dataclass, field
from enum import Enum

class EscalationLevel(str, Enum):
    L1 = "L1"
    L2 = "L2"
    L3 = "L3"

@dataclass
class BreachedTicket:
    id: str
    priority: str
    is_ai_issue: bool
    breached_at: float       # unix timestamp
    current_level: EscalationLevel = EscalationLevel.L1
    escalations: list[dict] = field(default_factory=list)

# Minutes after breach before escalating to next level
ESCALATION_THRESHOLDS = {
    "P1": {EscalationLevel.L1: 0, EscalationLevel.L2: 30, EscalationLevel.L3: 60},
    "P2": {EscalationLevel.L1: 0, EscalationLevel.L2: 240, EscalationLevel.L3: None},
}

def check_escalation(ticket: BreachedTicket,
                    notify_fn, now: float | None = None) -> None:
    """Called every 5 minutes for each open breached ticket."""
    now = now or time.time()
    elapsed_minutes = (now - ticket.breached_at) / 60
    thresholds = ESCALATION_THRESHOLDS.get(ticket.priority, {})

    for level in [EscalationLevel.L3, EscalationLevel.L2, EscalationLevel.L1]:
        threshold = thresholds.get(level)
        if threshold is None:
            continue
        if elapsed_minutes >= threshold:
            if ticket.current_level.value < level.value:
                ticket.current_level = level
                recipients = build_recipients(level, ticket.is_ai_issue)
                notify_fn(ticket.id, level, recipients)
                ticket.escalations.append({
                    "level": level,
                    "ts": now,
                    "recipients": recipients,
                })
            break

def build_recipients(level: EscalationLevel, is_ai: bool) -> list[str]:
    base = {
        EscalationLevel.L1: ["assigned_agent", "#ai-incidents"],
        EscalationLevel.L2: ["on-call-lead"],
        EscalationLevel.L3: ["engineering-manager", "vp-engineering"],
    }[level]
    if is_ai and level == EscalationLevel.L2:
        base.append("model-ops-on-call")
    return base
